import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const BookingConfirmation = () => {
  const [bookingData, setBookingData] = useState(null);
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [bookingConfirmed, setBookingConfirmed] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const storedBooking = localStorage.getItem('bookingData');
    const storedUser = localStorage.getItem('user');
    
    if (storedBooking && storedUser) {
      setBookingData(JSON.parse(storedBooking));
      setUserData(JSON.parse(storedUser));
      setLoading(false);
    } else {
      navigate('/search');
    }
  }, [navigate]);

  const handleConfirmBooking = () => {
    // Simulate booking confirmation
    setBookingConfirmed(true);
    
    // In a real app, this would make an API call to the backend
    // For demo, we'll just show the confirmation
    setTimeout(() => {
      // Clear booking data after confirmation
      localStorage.removeItem('bookingData');
      localStorage.removeItem('selectedBus');
      localStorage.removeItem('searchData');
    }, 2000);
  };

  const handleNewBooking = () => {
    localStorage.removeItem('bookingData');
    localStorage.removeItem('selectedBus');
    navigate('/search');
  };

  const handlePrintTicket = () => {
    window.print();
  };

  if (loading) {
    return (
      <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
        <p>Loading booking details...</p>
      </div>
    );
  }

  if (!bookingData || !userData) {
    return (
      <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
        <p>Booking details not found</p>
        <button className="btn" onClick={() => navigate('/search')}>
          Go to Search
        </button>
      </div>
    );
  }

  return (
    <div className="card" style={{ maxWidth: '600px', margin: '50px auto' }}>
      <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>
        {bookingConfirmed ? 'Booking Confirmed!' : 'Booking Confirmation'}
      </h2>

      {bookingConfirmed ? (
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '48px', color: '#28a745', marginBottom: '20px' }}>
            ✓
          </div>
          <h3 style={{ color: '#28a745', marginBottom: '20px' }}>
            Your booking has been confirmed successfully!
          </h3>
          <p style={{ marginBottom: '30px' }}>
            Booking ID: <strong>{bookingData.bookingId}</strong>
          </p>
        </div>
      ) : (
        <div>
          <p style={{ textAlign: 'center', marginBottom: '30px', color: '#666' }}>
            Please review your booking details before confirmation
          </p>
        </div>
      )}

      <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '5px', marginBottom: '20px' }}>
        <h4>Passenger Details</h4>
        <p><strong>Name:</strong> {userData.name}</p>
        <p><strong>Email:</strong> {userData.email}</p>
        <p><strong>Booking ID:</strong> {bookingData.bookingId}</p>
        <p><strong>Booking Date:</strong> {new Date(bookingData.timestamp).toLocaleDateString()}</p>
      </div>

      <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '5px', marginBottom: '20px' }}>
        <h4>Bus Details</h4>
        <p><strong>Bus Name:</strong> {bookingData.bus.busName}</p>
        <p><strong>Bus Type:</strong> {bookingData.bus.busType}</p>
        <p><strong>Departure:</strong> {bookingData.bus.departure}</p>
        <p><strong>Arrival:</strong> {bookingData.bus.arrival}</p>
        <p><strong>Duration:</strong> {bookingData.bus.duration}</p>
      </div>

      <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '5px', marginBottom: '20px' }}>
        <h4>Seat Details</h4>
        <p><strong>Seat Numbers:</strong> {bookingData.seats.map(s => s.number).join(', ')}</p>
        <p><strong>Number of Seats:</strong> {bookingData.seats.length}</p>
        <p><strong>Price per Seat:</strong> ₹{bookingData.bus.price}</p>
        <p><strong>Total Amount:</strong> <span style={{ fontSize: '18px', color: '#007bff', fontWeight: 'bold' }}>₹{bookingData.totalPrice}</span></p>
      </div>

      <div style={{ textAlign: 'center', marginTop: '30px' }}>
        {!bookingConfirmed ? (
          <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
            <button className="btn btn-secondary" onClick={() => navigate('/seats')}>
              ← Back to Seat Selection
            </button>
            <button className="btn" onClick={handleConfirmBooking}>
              Confirm Booking
            </button>
          </div>
        ) : (
          <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
            <button className="btn btn-secondary" onClick={handlePrintTicket}>
              Print Ticket
            </button>
            <button className="btn" onClick={handleNewBooking}>
              Book Another Ticket
            </button>
          </div>
        )}
      </div>

      <div style={{ 
        marginTop: '30px', 
        padding: '15px', 
        background: '#fff3cd', 
        border: '1px solid #ffeaa7', 
        borderRadius: '5px',
        fontSize: '14px',
        color: '#856404'
      }}>
        <strong>Important Information:</strong>
        <ul style={{ margin: '10px 0 0 20px' }}>
          <li>Please arrive at the boarding point 30 minutes before departure</li>
          <li>Carry a valid ID proof for verification</li>
          <li>This e-ticket is valid only for the specified date and time</li>
          <li>Cancellation policy applies as per terms and conditions</li>
        </ul>
      </div>
    </div>
  );
};

export default BookingConfirmation;
